import { useState } from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: Array<{ day: string; icon: string; high: number; low: number }>;
}

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  const getWeatherEmoji = (cond: string): string => {
    const normalized = cond.toLowerCase();
    if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
    if (normalized.includes('cloud')) return '☁️';
    if (normalized.includes('rain')) return '🌧️';
    if (normalized.includes('snow')) return '❄️';
    if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
    if (normalized.includes('fog') || normalized.includes('mist')) return '🌫️';
    if (normalized.includes('wind')) return '💨';
    return '🌤️';
  };

  return (
    <Card padding={24} shadow="md">
      <Stack direction="vertical" gap={24}>
        {/* Header with city */}
        <Stack direction="vertical" gap={4}>
          <Text variant="h2" color="var(--ggui-color-onSurface, #18181b)">
            {city}
          </Text>
        </Stack>

        {/* Current conditions section */}
        <Stack direction="vertical" gap={16}>
          {/* Temperature and condition */}
          <Row gap={16} align="start">
            <Stack direction="vertical" gap={8} align="start">
              <Text
                variant="h1"
                color="var(--ggui-color-primary-600, #0284c7)"
                weight="bold"
              >
                {temperature}°{unit}
              </Text>
              <Row gap={8} align="center">
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  {getWeatherEmoji(condition)} {condition}
                </Text>
              </Row>
            </Stack>
          </Row>

          {/* Divider */}
          <div
            style={{
              height: '1px',
              background: 'var(--ggui-color-outline, #d4d4d8)',
            }}
          />

          {/* Details row: Humidity and Wind */}
          <Row gap={32} justify="start">
            <Stack direction="vertical" gap={4}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-onSurface, #18181b)"
                weight="semibold"
              >
                {humidity}%
              </Text>
            </Stack>
            <Stack direction="vertical" gap={4}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind Speed
              </Text>
              <Text
                variant="body"
                color="var(--ggui-color-onSurface, #18181b)"
                weight="semibold"
              >
                {windSpeed} {unit === 'C' ? 'km/h' : 'mph'}
              </Text>
            </Stack>
          </Row>
        </Stack>

        {/* Divider before forecast */}
        <div
          style={{
            height: '1px',
            background: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        />

        {/* 5-day forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>
          <Row gap={8} wrap justify="between">
            {forecast.map((day, index) => (
              <Stack
                key={index}
                direction="vertical"
                gap={8}
                align="center"
                style={{
                  padding: 'var(--ggui-spacing-2, 8px)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  flex: '1',
                  minWidth: '80px',
                }}
              >
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  {day.day}
                </Text>
                <Text variant="h3" style={{ fontSize: 'var(--ggui-font-size-2xl, 24px)' }}>
                  {day.icon}
                </Text>
                <Stack direction="horizontal" gap={4} align="center">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurface, #18181b)"
                    weight="semibold"
                  >
                    {day.high}°
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {day.low}°
                  </Text>
                </Stack>
              </Stack>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
